import React from 'react';
import './Article.css';
import { stories } from './Stories.js';

const headline = 'Rats Orchestrate Takeover of New York City';
const author = 'Bernard Mendez';

class Article extends React.Component {

  newTab = () => {
    window.open(stories[this.props.index-1].url);
  }

  render () {
    return (
      <div className='Article' onClick={this.newTab}>
        <div>
          <img className='img' src={stories[this.props.index-1].image}></img>
        </div>

        <div className='headline'>
          <h3>{stories[this.props.index-1].title}</h3>
          <h4>By {stories[this.props.index-1].author}</h4>
        </div>
      </div>
    );
  }
}


export default Article;
